SELECT xksq.*, u.username AS user_name, k.coursename AS course_name, r.username AS reviewer_name
FROM selectionapplication xksq
LEFT JOIN user u ON xksq.user_id = u.id
LEFT JOIN course k ON xksq.course_id = k.id
LEFT JOIN user r ON xksq.reviewer_id = r.id

    
        AND xksq.id = #{id}
    
    
        AND xksq.user_id = #{userId}
    
    
        AND xksq.course_id = #{courseId}
    
    
        AND xksq.status = #{status}
